                <p className="font-semibold">{status.message}</p>
                {status.details && <p className="mt-1 font-mono opacity-80">{status.details}</p>}
              </div>
            </div>
          </div>

        </div>
      </div>

      <div className="mt-6 text-gray-300 text-[10px] text-center">
        Compact JSON/File Tester
      </div>
    </div>
  );
}

