  "sql": "SELECT * FROM public.users LIMIT 10;",
  "params": [],
  "requestId": "req-123"
};

// This is the command sent to the browser to request saved credentials
const FETCH_CREDENTIALS_REQUEST = {
  "type": "GET_SAVED_CREDENTIALS"
};

export default function App() {
  const [activeTab, setActiveTab] = useState<'text' | 'file'>('text');
  const [jsonInput, setJsonInput] = useState<string>('');
  const [status, setStatus] = useState<{ type: 'success' | 'error' | 'idle'; message: string; details?: string }>({
    type: 'idle',
    message: ''
  });

  // File Mode State
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [fileCommandType, setFileCommandType] = useState<string>('GIT_ZIP');
  const [credentialId, setCredentialId] = useState<string>('1');
  const [destination, setDestination] = useState<'github' | 'local' | 'both'>('github');
  const [pathInRepo, setPathInRepo] = useState<string>('');

  // --- Listeners for External Bridge ---
  useEffect(() => {
    // 1. Listen for window messages (standard postMessage)
    const handleMessage = (event: MessageEvent) => {
      // Check if message is intended for credential population
      if (event.data && (event.data.type === 'SAVED_CREDENTIALS_RESPONSE' || event.data.credentials)) {
        const content = typeof event.data === 'string' ? event.data : JSON.stringify(event.data, null, 2);
        setJsonInput(content);
        setStatus({ type: 'success', message: 'Credentials received from browser!' });
      }
    };

    window.addEventListener('message', handleMessage);

    // 2. Expose a global function for the Muul browser to call directly
    window.updateJsonInput = (data: any) => {
      const content = typeof data === 'string' ? data : JSON.stringify(data, null, 2);
      setJsonInput(content);
      setStatus({ type: 'success', message: 'Input updated by external source.' });
    };

    return () => {
      window.removeEventListener('message', handleMessage);
      delete window.updateJsonInput;
    };
  }, []);

  const resetStatus = () => setStatus({ type: 'idle', message: '' });

  const fillJson = (data: any) => {
    setJsonInput(JSON.stringify(data, null, 2));
    resetStatus();
  };

  const handleFetchCredentials = () => {
    // Fill the text area with the request command
    fillJson(FETCH_CREDENTIALS_REQUEST);

    // Immediately notify the external bridge
    if (window.externalMessage && window.externalMessage.send) {
      window.externalMessage.send(JSON.stringify(FETCH_CREDENTIALS_REQUEST));
      setStatus({ type: 'success', message: 'Requested saved credentials from browser...' });
    } else {
      setStatus({ type: 'error', message: 'Bridge not detected.', details: 'The externalMessage.send handler is missing.' });
    }
  };

  const handleSendText = () => {
    if (!jsonInput.trim()) {
      setStatus({ type: 'error', message: 'Please enter JSON content.' });
      return;
    }

    try {
      JSON.parse(jsonInput);
      if (window.externalMessage && window.externalMessage.send) {
        window.externalMessage.send(jsonInput);
        setStatus({ type: 'success', message: 'JSON Command Sent!' });
      } else {
        setStatus({ type: 'success', message: 'JSON Valid (Bridge Simulated)' });
      }
    } catch (error: any) {
      setStatus({ type: 'error', message: 'Invalid JSON', details: error.message });
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      setSelectedFile(e.target.files[0]);
      resetStatus();
    }
  };

  const handleSendFile = () => {
    if (!selectedFile) return;
    const reader = new FileReader();
    reader.onload = () => {
      const payload = JSON.stringify({
        type: fileCommandType,
        name: selectedFile.name,
        dataUrl: reader.result,
        target: destination,
        credentialId,
        pathInRepo
      });
      if (window.externalMessage && window.externalMessage.send) {
        window.externalMessage.send(payload);
        setStatus({ type: 'success', message: 'File command sent!' });
      }
    };
    reader.readAsDataURL(selectedFile);
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-4 font-sans">
      <div className="w-full max-w-md bg-white rounded-xl shadow-xl border border-gray-200 overflow-hidden">
        <div className="bg-gray-800 px-6 py-4 flex items-center justify-between">
          <h1 className="text-white font-bold tracking-tight">JSON Test Page</h1>
          <div className="w-2 h-2 rounded-full bg-green-400 animate-pulse"></div>
        </div>

        <div className="flex bg-gray-100 p-1 m-4 rounded-lg">
          <button
            onClick={() => { setActiveTab('text'); resetStatus(); }}
            className={`flex-1 py-2 text-xs font-bold rounded-md transition-all ${activeTab === 'text' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}
          >
            JSON TEXT
          </button>
          <button
            onClick={() => { setActiveTab('file'); resetStatus(); }}
            className={`flex-1 py-2 text-xs font-bold rounded-md transition-all ${activeTab === 'file' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}
          >
            SEND FILE
          </button>
        </div>

        <div className="px-6 pb-6 space-y-4">
          {activeTab === 'text' ? (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-2">
                <button onClick={() => fillJson(PRINT_JSON)} className="text-[10px] py-2 bg-gray-100 border border-gray-200 rounded font-bold text-gray-600 hover:bg-gray-200 transition-colors uppercase tracking-wider">Print Template</button>
                <button onClick={() => fillJson(GIT_TEMPLATE_JSON)} className="text-[10px] py-2 bg-gray-100 border border-gray-200 rounded font-bold text-gray-600 hover:bg-gray-200 transition-colors uppercase tracking-wider">Git Template</button>
                <button onClick={() => fillJson(DATABASE_JSON)} className="text-[10px] py-2 bg-gray-100 border border-gray-200 rounded font-bold text-gray-600 hover:bg-gray-200 transition-colors uppercase tracking-wider">DB Query</button>
                <button onClick={handleFetchCredentials} className="text-[10px] py-2 bg-blue-600 border border-blue-700 rounded font-bold text-white hover:bg-blue-700 transition-colors shadow-sm uppercase tracking-wider">Fetch DB Credential</button>
              </div>

              <div className="relative group">
                <div className="absolute top-2 right-3 text-[10px] text-gray-400 font-mono">JSON</div>
                <textarea
                  value={jsonInput}
                  onChange={(e) => setJsonInput(e.target.value)}
                  placeholder='Paste JSON here or use buttons above...'
                  className={`w-full h-56 p-4 rounded-lg border bg-gray-50 text-xs font-mono focus:ring-2 focus:ring-blue-100 focus:outline-none transition-all resize-none ${status.type === 'error' ? 'border-red-300' : 'border-gray-200'}`}
                  spellCheck={false}
                />
              </div>

              <button
                onClick={handleSendText}
                className="w-full py-3 bg-gray-900 hover:bg-black text-white rounded-lg font-bold text-sm shadow-md active:transform active:scale-[0.98] transition-all"
              >
                SEND JSON COMMAND
              </button>
            </div>
          ) : (
            <div className="space-y-4">
               <div>
                <label className="text-[10px] font-bold text-gray-400 uppercase ml-1">Command Type</label>
                <select value={fileCommandType} onChange={(e) => setFileCommandType(e.target.value)} className="w-full mt-1 p-2 bg-gray-50 border border-gray-200 rounded-lg text-xs font-medium focus:outline-none">
                  <option value="GIT_ZIP">GIT_ZIP</option>
                  <option value="GIT_FILE">GIT_FILE</option>
                  <option value="DATABASE">DATABASE</option>
                </select>
              </div>

              <input type="file" onChange={handleFileChange} className="w-full text-xs text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-xs file:font-bold file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100 transition-all cursor-pointer" />

              <button
                onClick={handleSendFile}
                disabled={!selectedFile}
                className={`w-full py-3 rounded-lg font-bold text-sm shadow-md transition-all ${selectedFile ? 'bg-blue-600 hover:bg-blue-700 text-white' : 'bg-gray-200 text-gray-400 cursor-not-allowed'}`}
              >
                SEND FILE CONTENT
              </button>
            </div>
          )}

          {status.type !== 'idle' && (
            <div className={`p-3 rounded-lg border text-xs flex items-center gap-3 animate-in fade-in slide-in-from-top-2 duration-300 ${status.type === 'error' ? 'bg-red-50 text-red-700 border-red-100' : 'bg-green-50 text-green-700 border-green-100'}`}>
              <div className={`w-2 h-2 rounded-full ${status.type === 'error' ? 'bg-red-500' : 'bg-green-500'}`}></div>
              <div className="flex-1">
                <p className="font-bold">{status.message}</p>
                {status.details && <p className="mt-0.5 opacity-70 font-mono text-[10px]">{status.details}</p>}
              </div>
            </div>
          )}
        </div>
      </div>
      <p className="mt-8 text-[10px] text-gray-400 uppercase tracking-widest font-semibold">External Bridge Active</p>
    </div>
  );
}

import React, { useState, useEffect } from 'react';

