        const content = typeof event.data === 'string' ? event.data : JSON.stringify(event.data, null, 2);
        setResultData(content);
        setStatus({ type: 'success', message: 'Data received from Browser!' });
      }
    };

    window.addEventListener('message', handleMessage);

    // 2. Expose global function for the browser to call
    window.updateBrowserResult = (data: any) => {
      const content = typeof data === 'string' ? data : JSON.stringify(data, null, 2);
      setResultData(content);
      setStatus({ type: 'success', message: 'Result updated by external bridge.' });
    };

    return () => {
      window.removeEventListener('message', handleMessage);
      delete window.updateBrowserResult;
    };
  }, []);

  const resetStatus = () => setStatus({ type: 'idle', message: '' });

  const sendToExternal = (payload: string, successMessage: string) => {
    try {
      if (window.externalMessage && window.externalMessage.send) {
        window.externalMessage.send(payload);
        setStatus({ type: 'success', message: successMessage });
      } else {
        console.log('Simulated Send:', payload);
        setStatus({ type: 'success', message: `${successMessage} (Bridge Simulated)` });
      }
    } catch (err: any) {
      setStatus({ type: 'error', message: 'Send failed.', details: err.message });
    }
  };

  const fillJson = (data: any) => {
    setJsonInput(JSON.stringify(data, null, 2));
    resetStatus();
  };

  // The requested fetch method
  const handleFetchCredentials = async () => {
    const cmd = JSON.stringify({ type: 'GET_SAVED_CREDENTIALS', requestId: 'list-' + Date.now() });
    setJsonInput(cmd);
    resetStatus();
    try {
      const res = await window.externalMessage?.send(cmd);
      const entries = res?.entries || res?.data?.entries || [];
      setResultData(JSON.stringify(entries, null, 2));
      setStatus({ type: 'success', message: 'Credentials received' });
    } catch (e: any) {
      setStatus({ type: 'error', message: 'Fetch failed', details: e.message });
    }
  };

  const handleSendText = () => {
    if (!jsonInput.trim()) {
      setStatus({ type: 'error', message: 'Please enter JSON content.' });
      return;
    }
    try {
      JSON.parse(jsonInput);
      sendToExternal(jsonInput, 'JSON Command Sent!');
    } catch (error: any) {
      setStatus({ type: 'error', message: 'Invalid JSON', details: error.message });
    }
  };

  const handleSendFile = () => {
    if (!selectedFile) return;
    const reader = new FileReader();
    reader.onload = () => {
      const payload = JSON.stringify({
        type: fileCommandType,
        name: selectedFile.name,
        dataUrl: reader.result,
        target: destination,
        credentialId,
        pathInRepo
