  });

  // --- External Bridge Logic ---
  useEffect(() => {
    // 1. Listen for standard window messages
    const handleMessage = (event: MessageEvent) => {
      if (event.data && (event.data.type === 'SAVED_CREDENTIALS_RESPONSE' || event.data.credentials)) {
        const content = typeof event.data === 'string' ? event.data : JSON.stringify(event.data, null, 2);
        setResultData(content);
        setStatus({ type: 'success', message: 'Data received from Browser!' });
      }
    };

    // 2. Listen for pushed replies
    const handleExternalResult = (e: any) => {
      const data = e.detail || e;
      setResultData(JSON.stringify(data, null, 2));
      setStatus({ type: 'success', message: 'Pushed reply received!' });
    };

    window.addEventListener('message', handleMessage);
    window.addEventListener('external:result', handleExternalResult);

    // 3. Expose global function for the browser to call
    window.updateBrowserResult = (data: any) => {
      const content = typeof data === 'string' ? data : JSON.stringify(data, null, 2);
      setResultData(content);
      setStatus({ type: 'success', message: 'Result updated by external bridge.' });
