        setResultData(JSON.stringify(res, null, 2));
        setStatus({ type: 'success', message: 'Command Sent and Response Received!' });
      } else {
        console.log('Simulated Send:', cmd);
        setStatus({ type: 'success', message: 'JSON Valid (Bridge Simulated)' });
      }
    } catch (error: any) {
      setStatus({ type: 'error', message: 'Invalid JSON or Send Error', details: error.message });
