                    <button onClick={() => fillJson(PRINT_JSON_2)} className="flex-1 text-[10px] py-2 bg-gray-50 border border-gray-200 rounded font-bold text-gray-600 hover:bg-gray-100 uppercase tracking-tighter">Print Template 2</button>
